def lbs(arr):
    """
    Compute the length of the Longest Bitonic Subsequence (LBS) in `arr`.
    Equivalent to the provided C++ implementation.
    """
    n = len(arr)
    if n == 0:
        return 0
    # Longest Increasing Subsequence (LIS) ending at each position
    lis = [1] * n
    for i in range(1, n):
        for j in range(i):
            if arr[i] > arr[j] and lis[i] < lis[j] + 1:
                lis[i] = lis[j] + 1
    # Longest Decreasing Subsequence (LDS) starting at each position
    lds = [1] * n
    for i in range(n - 2, -1, -1):
        for j in range(n - 1, i, -1):
            if arr[i] > arr[j] and lds[i] < lds[j] + 1:
                lds[i] = lds[j] + 1
    # Combine LIS and LDS for max bitonic subsequence length
    max_len = lis[0] + lds[0] - 1
    for i in range(1, n):
        max_len = max(max_len, lis[i] + lds[i] - 1)
    return max_len

