def binomial_coeff_sum(n: int) -> int:
    """
    Builds Pascal's triangle up to row `n` and returns the sum of the
    elements in the n-th row, i.e. Σ_{k=0..n} C(n, k) = 2^n.
    """
    # Create a (n+1) x (n+1) 2-D list initialized with zeros
    C = [[0] * (n + 1) for _ in range(n + 1)]
    # Fill the Pascal's triangle table
    for i in range(n + 1):
        for j in range(min(i, n) + 1):
            if j == 0 or j == i:
                C[i][j] = 1
            else:
                C[i][j] = C[i - 1][j - 1] + C[i - 1][j]
    # Sum of the coefficients in the n-th row
    return sum(C[n][i] for i in range(n + 1))

